1	import { useRef, useEffect, useCallback } from "react";
2	import { tokens } from "../tokens/tokens";
3	
4	type VuMeterProps = {
5	  level: number;
6	  peak?: number;
7	  clip?: boolean;
8	  width?: number;
9	  height?: number;
10	};
11	
12	const DEFAULT_WIDTH = 12;
13	const DEFAULT_HEIGHT = 128;
14	const PEAK_DECAY_RATE = 0.005;
15	const CLIP_INDICATOR_SIZE = 4;
16	
17	function getLevelColor(normalizedY: number): string {
18	  if (normalizedY > 0.9) return tokens.color.red;
19	  if (normalizedY > 0.7) return tokens.color.amber;
20	  return tokens.color.green;
21	}
22	
23	function buildAriaLabel(level: number, clip: boolean): string {
24	  const pct = Math.round(level * 100);
25	  return clip
26	    ? `Audio level: ${String(pct)}% (clipping)`
27	    : `Audio level: ${String(pct)}%`;
28	}
29	
30	export function VuMeter({
31	  level: rawLevel,
32	  peak,
33	  clip,
34	  width = DEFAULT_WIDTH,
35	  height = DEFAULT_HEIGHT,
36	}: VuMeterProps): React.JSX.Element {
37	  const canvasRef = useRef<HTMLCanvasElement>(null);
38	  const peakHoldRef = useRef(peak ?? 0);
39	  const rafRef = useRef(0);
40	  const animatingRef = useRef(false);
41	
42	  const level = Math.min(1, Math.max(0, rawLevel));
43	
44	  const draw = useCallback(
45	    (ctx: CanvasRenderingContext2D): void => {
46	      const w = width;
47	      const h = height;
48	
49	      // Background
50	      ctx.fillStyle = tokens.color.black;
51	      ctx.fillRect(0, 0, w, h);
52	
53	      // Level bar (drawn from bottom up)
54	      const barHeight = level * h;
55	      const barTop = h - barHeight;
56	
57	      for (let y = barTop; y < h; y++) {
58	        const normalizedY = 1 - y / h;
59	        ctx.fillStyle = getLevelColor(normalizedY);
60	        ctx.fillRect(0, y, w, 1);
61	      }
62	
63	      // Peak hold line
64	      const currentPeak = peakHoldRef.current;
65	      if (currentPeak > 0) {
66	        const peakY = h - currentPeak * h;
67	        ctx.strokeStyle = tokens.color.white;
68	        ctx.lineWidth = 1;
69	        ctx.beginPath();
70	        ctx.moveTo(0, peakY);
71	        ctx.lineTo(w, peakY);
72	        ctx.stroke();
73	      }
74	
75	      // Clip indicator
76	      if (clip === true) {
77	        ctx.fillStyle = tokens.color.red;
78	        ctx.fillRect(
79	          (w - CLIP_INDICATOR_SIZE) / 2,
80	          1,
81	          CLIP_INDICATOR_SIZE,
82	          CLIP_INDICATOR_SIZE,
83	        );
84	      }
85	    },
86	    [level, clip, width, height],
87	  );
88	
89	  useEffect(() => {
90	    const canvas = canvasRef.current;
91	    if (canvas === null) return;
92	    const ctx = canvas.getContext("2d");
93	    if (ctx === null) return;
94	
95	    // Update peak hold from prop or current level
96	    if (peak !== undefined) {
97	      peakHoldRef.current = peak;
98	    } else if (level > peakHoldRef.current) {
99	      peakHoldRef.current = level;
100	    }
101	
102	    draw(ctx);
103	
104	    // Animate peak decay
105	    if (
106	      peak === undefined &&
107	      peakHoldRef.current > 0 &&
108	      !animatingRef.current
109	    ) {
110	      animatingRef.current = true;
111	      const animate = (): void => {
112	        if (peakHoldRef.current > 0) {
113	          peakHoldRef.current = Math.max(
114	            0,
115	            peakHoldRef.current - PEAK_DECAY_RATE,
116	          );
117	          draw(ctx);
118	          rafRef.current = requestAnimationFrame(animate);
119	        } else {
120	          animatingRef.current = false;
121	        }
122	      };
123	      rafRef.current = requestAnimationFrame(animate);
124	    }
125	
126	    return (): void => {
127	      cancelAnimationFrame(rafRef.current);
128	      animatingRef.current = false;
129	    };
130	  }, [level, peak, clip, draw]);
131	
132	  const isClipping = clip === true;
133	
134	  return (
135	    <canvas
136	      ref={canvasRef}
137	      role="img"
138	      aria-label={buildAriaLabel(level, isClipping)}
139	      width={width}
140	      height={height}
141	    />
142	  );
143	}
