1	import { useRef, useEffect, useCallback, useState } from "react";
2	import { tokens } from "../tokens/tokens";
3	
4	type RotaryKnobProps = {
5	  value: number;
6	  min: number;
7	  max: number;
8	  step?: number;
9	  onChange: (value: number) => void;
10	  label: string;
11	  size?: number;
12	  valueText?: string;
13	};
14	
15	const START_ANGLE = 0.75 * Math.PI;
16	const END_ANGLE = 2.25 * Math.PI;
17	const ARC_RANGE = END_ANGLE - START_ANGLE;
18	const DRAG_SENSITIVITY = 200;
19	
20	function clamp(v: number, min: number, max: number): number {
21	  return Math.min(max, Math.max(min, v));
22	}
23	
24	function snapToStep(raw: number, step: number): number {
25	  return Math.round(raw / step) * step;
26	}
27	
28	function drawKnob(
29	  ctx: CanvasRenderingContext2D,
30	  size: number,
31	  ratio: number,
32	): void {
33	  const cx = size / 2;
34	  const cy = size / 2;
35	  const radius = size / 2 - tokens.border.width * 2;
36	
37	  ctx.clearRect(0, 0, size, size);
38	
39	  // Outer circle
40	  ctx.beginPath();
41	  ctx.arc(cx, cy, radius, 0, 2 * Math.PI);
42	  ctx.strokeStyle = tokens.color.gray700;
43	  ctx.lineWidth = tokens.border.width;
44	  ctx.stroke();
45	
46	  // Value arc
47	  const valueAngle = START_ANGLE + ratio * ARC_RANGE;
48	  ctx.beginPath();
49	  ctx.arc(cx, cy, radius, START_ANGLE, valueAngle);
50	  ctx.strokeStyle = tokens.color.blue;
51	  ctx.lineWidth = tokens.border.width + 1;
52	  ctx.lineCap = "round";
53	  ctx.stroke();
54	
55	  // Pointer line from center
56	  const pointerLen = radius * 0.7;
57	  const px = cx + Math.cos(valueAngle) * pointerLen;
58	  const py = cy + Math.sin(valueAngle) * pointerLen;
59	  ctx.beginPath();
60	  ctx.moveTo(cx, cy);
61	  ctx.lineTo(px, py);
62	  ctx.strokeStyle = tokens.color.white;
63	  ctx.lineWidth = tokens.border.width;
64	  ctx.lineCap = "round";
65	  ctx.stroke();
66	}
67	
68	export function RotaryKnob({
69	  value,
70	  min,
71	  max,
72	  step = 1,
73	  onChange,
74	  label,
75	  size = 48,
76	  valueText,
77	}: RotaryKnobProps): React.JSX.Element {
78	  const canvasRef = useRef<HTMLCanvasElement>(null);
79	  const wrapperRef = useRef<HTMLDivElement>(null);
80	  const listenersRef = useRef<AbortController | null>(null);
81	  const [isFocusVisible, setIsFocusVisible] = useState(false);
82	
83	  const ratio = max === min ? 0 : (value - min) / (max - min);
84	
85	  useEffect(() => {
86	    const canvas = canvasRef.current;
87	    if (!canvas) return;
88	    const ctx = canvas.getContext("2d");
89	    if (!ctx) return;
90	    drawKnob(ctx, size, ratio);
91	  }, [value, min, max, size, ratio]);
92	
93	  // Cleanup drag listeners on unmount
94	  useEffect(() => {
95	    return (): void => {
96	      listenersRef.current?.abort();
97	    };
98	  }, []);
99	
100	  const commit = useCallback(
101	    (next: number): void => {
102	      onChange(clamp(snapToStep(next, step), min, max));
103	    },
104	    [onChange, min, max, step],
105	  );
106	
107	  const handleKeyDown = useCallback(
108	    (e: React.KeyboardEvent): void => {
109	      switch (e.key) {
110	        case "ArrowUp":
111	        case "ArrowRight":
112	          e.preventDefault();
113	          commit(value + step);
114	          break;
115	        case "ArrowDown":
116	        case "ArrowLeft":
117	          e.preventDefault();
118	          commit(value - step);
119	          break;
120	        case "PageUp":
121	          e.preventDefault();
122	          commit(value + step * 10);
123	          break;
124	        case "PageDown":
125	          e.preventDefault();
126	          commit(value - step * 10);
127	          break;
128	        case "Home":
129	          e.preventDefault();
130	          commit(min);
131	          break;
132	        case "End":
133	          e.preventDefault();
134	          commit(max);
135	          break;
136	      }
137	    },
138	    [value, step, min, max, commit],
139	  );
140	
141	  const handlePointerDown = useCallback(
142	    (e: React.PointerEvent): void => {
143	      e.preventDefault();
144	      const target = e.target as HTMLElement;
145	      if (typeof target.setPointerCapture === "function") {
146	        target.setPointerCapture(e.pointerId);
147	      }
148	      const startY = e.clientY;
149	      const startValue = value;
150	      const range = max - min;
151	
152	      listenersRef.current?.abort();
153	      const controller = new AbortController();
154	      listenersRef.current = controller;
155	
156	      document.addEventListener(
157	        "pointermove",
158	        (moveEvent: PointerEvent) => {
159	          const delta = startY - moveEvent.clientY;
160	          const fraction = delta / DRAG_SENSITIVITY;
161	          commit(startValue + fraction * range);
162	        },
163	        { signal: controller.signal },
164	      );
165	
166	      document.addEventListener(
167	        "pointerup",
168	        () => {
169	          controller.abort();
170	        },
171	        { signal: controller.signal },
172	      );
173	    },
174	    [value, max, min, commit],
175	  );
176	
177	  return (
178	    <div
179	      ref={wrapperRef}
180	      role="slider"
181	      tabIndex={0}
182	      aria-valuemin={min}
183	      aria-valuemax={max}
184	      aria-valuenow={value}
185	      aria-valuetext={valueText}
186	      aria-label={label}
187	      onKeyDown={handleKeyDown}
188	      onFocus={(e) => {
189	        if (
190	          e.target === wrapperRef.current &&
191	          e.target.matches(":focus-visible")
192	        ) {
193	          setIsFocusVisible(true);
194	        }
195	      }}
196	      onBlur={() => {
197	        setIsFocusVisible(false);
198	      }}
199	      style={{
200	        display: "inline-flex",
201	        flexDirection: "column",
202	        alignItems: "center",
203	        gap: tokens.space[1],
204	        userSelect: "none",
205	        outline: isFocusVisible ? `2px solid ${tokens.color.blue}` : "none",
206	        outlineOffset: "2px",
207	        borderRadius: "2px",
208	      }}
209	    >
210	      <span
211	        style={{
212	          fontSize: tokens.text.xs,
213	          fontFamily: tokens.font.mono,
214	          color: tokens.color.gray300,
215	        }}
216	      >
217	        {label}
218	      </span>
219	      <canvas
220	        ref={canvasRef}
221	        width={size}
222	        height={size}
223	        onPointerDown={handlePointerDown}
224	        style={{ cursor: "grab" }}
225	      />
226	      <span
227	        style={{
228	          fontSize: tokens.text.xs,
229	          fontFamily: tokens.font.mono,
230	          color: tokens.color.white,
231	        }}
232	      >
233	        {value}
234	      </span>
235	    </div>
236	  );
237	}
