134	    const rect = canvas.getBoundingClientRect();
135	    renderPianoRoll({
136	      ctx,
137	      width: rect.width,
138	      height: rect.height,
139	      view,
140	      notes,
141	      selectedNoteIds: [...selectedNoteIds],
142	      cursorSeconds,
143	      bpm,
144	      clipStartTime,
145	      clipDuration,
146	      tool,
147	      velocityLaneHeight: PR_VELOCITY_LANE_HEIGHT,
148	    });
149	  }, [
150	    view,
151	    notes,
152	    selectedNoteIds,
153	    cursorSeconds,
154	    bpm,
155	    clipStartTime,
156	    clipDuration,
157	    tool,
158	  ]);
