208	  // Wheel: ctrl+wheel for zoom, plain wheel for scroll
209	  // Attached via useEffect with { passive: false } so preventDefault() works
210	  useEffect(() => {
211	    const canvas = canvasRef.current;
212	    if (canvas === null) return;
213	
214	    const handleWheel = (e: WheelEvent): void => {
