1	import { useEffect } from "react";
2	import type { CommandRegistry } from "@ui/keyboard/command-registry";
3	import type { ShortcutMap } from "@ui/keyboard/shortcut-map";
4	import type { UndoManager } from "@state/undo/index";
5	
6	export function useSessionShortcuts(
7	  registry: CommandRegistry,
8	  shortcuts: ShortcutMap,
9	  undoManager: UndoManager,
10	  saveNow: () => Promise<void>,
11	): void {
12	  useEffect(() => {
13	    registry.register({
14	      id: "edit.undo",
15	      label: "Undo",
16	      execute: () => {
17	        undoManager.undo();
18	      },
19	    });
20	
21	    registry.register({
22	      id: "edit.redo",
23	      label: "Redo",
24	      execute: () => {
25	        undoManager.redo();
26	      },
27	    });
28	
29	    registry.register({
30	      id: "session.save",
31	      label: "Save",
32	      execute: () => {
33	        void saveNow();
34	      },
35	    });
36	
37	    // Ctrl+Z / Cmd+Z for undo
38	    shortcuts.bind({ key: "z", ctrl: true, commandId: "edit.undo" });
39	    shortcuts.bind({ key: "z", meta: true, commandId: "edit.undo" });
40	
41	    // Ctrl+Shift+Z / Cmd+Shift+Z for redo
42	    shortcuts.bind({
43	      key: "z",
44	      ctrl: true,
45	      shift: true,
46	      commandId: "edit.redo",
47	    });
48	    shortcuts.bind({
49	      key: "z",
50	      meta: true,
51	      shift: true,
52	      commandId: "edit.redo",
53	    });
54	
55	    // Ctrl+S / Cmd+S for save
56	    shortcuts.bind({ key: "s", ctrl: true, commandId: "session.save" });
57	    shortcuts.bind({ key: "s", meta: true, commandId: "session.save" });
58	
59	    return () => {
60	      registry.unregister("edit.undo");
61	      registry.unregister("edit.redo");
62	      registry.unregister("session.save");
63	      shortcuts.unbind("edit.undo");
64	      shortcuts.unbind("edit.redo");
65	      shortcuts.unbind("session.save");
66	    };
67	  }, [registry, shortcuts, undoManager, saveNow]);
68	}
