import { useEffect, useState } from "react";
import styles from "./ActionToast.module.css";

const TOAST_DURATION = 1200;
const FADE_DURATION = 100;

type ActionToastProps = {
  message: string | null;
};

export function ActionToast({ message }: ActionToastProps): React.JSX.Element | null {
  const [visible, setVisible] = useState<string | null>(null);
  const [hiding, setHiding] = useState(false);

  useEffect(() => {
    if (message === null) return;
    setVisible(message);
    setHiding(false);

    const fadeTimer = setTimeout(() => {
      setHiding(true);
    }, TOAST_DURATION - FADE_DURATION);

    const hideTimer = setTimeout(() => {
      setVisible(null);
      setHiding(false);
    }, TOAST_DURATION);

    return () => {
      clearTimeout(fadeTimer);
      clearTimeout(hideTimer);
    };
  }, [message]);

  if (visible === null) return null;

  return (
    <div
      className={`${styles["toast"]}${hiding ? ` ${styles["hiding"]}` : ""}`}
      role="status"
      aria-live="polite"
    >
      {visible}
    </div>
  );
}

