        flexDirection: "column",
        height: "100vh",
        backgroundColor: "var(--color-black)",
      }}
    >
      <Toolbar />
      <ErrorBoundary fallbackLabel="Panel crashed">
        <div
          style={{
            display: "flex",
            flexDirection: "column",
            flex: 1,
            overflow: "hidden",
          }}
        >
          <ArrangementPanel />
          <MixerPanel />
          <div style={{ display: "flex", overflow: "hidden" }}>
            <div style={{ flex: 1 }}>
              <InstrumentPanel />
            </div>
            <div style={{ flex: 1 }}>
              <MediaPoolPanel pool={pool} />
            </div>
          </div>
        </div>
      </ErrorBoundary>
      <KeyboardShortcutsPanel
        open={shortcutsOpen}
        onClose={() => {
          setShortcutsOpen(false);
        }}
      />
      <RecoveryDialog
        open={showRecovery}
        warnings={recoveryWarnings}
        onAccept={() => {
          setDismissed(true);
        }}
        onDiscard={() => {
          hydrateStore(createDefaultSession());
          setDismissed(true);
        }}
      />
    </div>
  );
}

