59	export type PianoRollInteractions = {
60	  cursor: string;
61	  onPointerDown: (e: React.PointerEvent<HTMLCanvasElement>) => void;
62	  onPointerMove: (e: React.PointerEvent<HTMLCanvasElement>) => void;
63	  onPointerUp: (e: React.PointerEvent<HTMLCanvasElement>) => void;
64	  deleteSelectedNotes: () => void;
