74	  const secPerBeat = 60 / bpm;
75	  switch (snap) {
76	    case "1/4":
77	      return secPerBeat;
78	    case "1/8":
79	      return secPerBeat / 2;
80	    case "1/16":
81	      return secPerBeat / 4;
82	    case "1/8T":
83	      return secPerBeat / 3;
84	    case "1/16T":
85	      return secPerBeat / 6;
86	  }
87	}
