89	export function usePianoRollInteractions(
90	  clipId: string | null,
91	  view: PianoRollViewState,
92	  tool: PianoRollTool,
93	  gridSnap: PianoRollGridSnap,
94	): PianoRollInteractions {
95	  const dragRef = useRef<DragState>({ kind: "idle" });
96	  const [cursor, setCursor] = useState(
97	    clipId !== null && tool === "pencil" ? "crosshair" : "default",
98	  );
99	
100	  const getCanvasPos = useCallback(
101	    (e: React.MouseEvent<HTMLCanvasElement>): { x: number; y: number } => {
102	      const rect = e.currentTarget.getBoundingClientRect();
103	      return { x: e.clientX - rect.left, y: e.clientY - rect.top };
104	    },
105	    [],
106	  );
107	
108	  const getNotes = useCallback((): readonly MIDINoteEvent[] => {
109	    if (clipId === null) return [];
110	    const clip = useDawStore.getState().clips[clipId];
111	    if (clip === undefined || !isMidiClip(clip)) return [];
112	    return clip.noteEvents;
113	  }, [clipId]);
114	
115	  const onPointerDown = useCallback(
116	    (e: React.PointerEvent<HTMLCanvasElement>): void => {
117	      if (clipId === null) return;
118	
119	      const { x, y } = getCanvasPos(e);
120	      const state = useDawStore.getState();
121	      const notes = getNotes();
122	      const canvasHeight = e.currentTarget.getBoundingClientRect().height;
123	      const hit = pianoRollHitTest(
124	        x,
125	        y,
126	        view,
127	        notes,
128	        canvasHeight,
129	        PR_VELOCITY_LANE_HEIGHT,
130	      );
131	
132	      switch (tool) {
133	        case "pencil": {
134	          if (hit.kind === "empty-grid") {
135	            const snappedTime = pianoRollSnapToGrid(
136	              hit.timeSeconds,
137	              state.bpm,
138	              gridSnap,
139	            );
140	            const dur = gridDuration(state.bpm, gridSnap);
141	            const noteId = generateNoteId();
142	            const note: MIDINoteEvent = {
143	              id: noteId,
144	              pitch: hit.pitch,
145	              velocity: 100,
146	              startTime: Math.max(0, snappedTime),
147	              duration: dur,
148	            };
149	            const cmd = new AddNoteCommand(clipId, note);
150	            cmd.execute();
151	            sharedUndoManager.push(cmd);
152	
153	            e.currentTarget.setPointerCapture(e.pointerId);
154	            dragRef.current = {
155	              kind: "draw-note",
156	              clipId,
157	              noteId,
158	              startTime: note.startTime,
159	              pitch: note.pitch,
160	            };
161	          }
162	          break;
163	        }
164	        case "select": {
165	          if (hit.kind === "note-body") {
166	            if (e.shiftKey) {
167	              const current = [...state.selectedNoteIds];
168	              const idx = current.indexOf(hit.noteId);
169	              if (idx >= 0) {
170	                current.splice(idx, 1);
171	              } else {
172	                current.push(hit.noteId);
173	              }
174	              state.setSelectedNoteIds(current);
175	            } else {
176	              if (!state.selectedNoteIds.includes(hit.noteId)) {
177	                state.setSelectedNoteIds([hit.noteId]);
178	              }
179	            }
180	
181	            // Find note for drag
182	            const note = notes.find((n) => n.id === hit.noteId);
183	            if (note !== undefined) {
184	              e.currentTarget.setPointerCapture(e.pointerId);
185	              dragRef.current = {
186	                kind: "move-note",
187	                noteId: hit.noteId,
188	                clipId,
189	                startX: x,
190	                startY: y,
191	                origStartTime: note.startTime,
192	                origPitch: note.pitch,
193	              };
194	            }
195	          } else if (
196	            hit.kind === "note-left-edge" ||
197	            hit.kind === "note-right-edge"
198	          ) {
199	            state.setSelectedNoteIds([hit.noteId]);
200	            const note = notes.find((n) => n.id === hit.noteId);
201	            if (note !== undefined) {
202	              e.currentTarget.setPointerCapture(e.pointerId);
203	              dragRef.current = {
204	                kind: "resize-note",
205	                noteId: hit.noteId,
206	                clipId,
207	                startX: x,
208	                origStartTime: note.startTime,
209	                origDuration: note.duration,
210	                edge: hit.kind === "note-left-edge" ? "left" : "right",
211	              };
212	            }
213	          } else if (hit.kind === "empty-grid") {
214	            if (!e.shiftKey) {
215	              state.setSelectedNoteIds([]);
216	            }
217	            e.currentTarget.setPointerCapture(e.pointerId);
218	            dragRef.current = { kind: "rubber-band", startX: x, startY: y };
219	          }
