221	        }
222	        case "erase": {
223	          if (
224	            hit.kind === "note-body" ||
225	            hit.kind === "note-left-edge" ||
226	            hit.kind === "note-right-edge"
227	          ) {
228	            const cmd = new RemoveNoteCommand(clipId, hit.noteId);
229	            cmd.execute();
