239	  const onPointerMove = useCallback(
240	    (e: React.PointerEvent<HTMLCanvasElement>): void => {
241	      const { x, y } = getCanvasPos(e);
242	      const drag = dragRef.current;
243	      const state = useDawStore.getState();
244	
245	      if (drag.kind === "idle") {
246	        // Update cursor based on hover
247	        if (clipId === null) {
248	          setCursor("default");
249	          return;
250	        }
251	
252	        const notes = getNotes();
253	        const canvasHeight = e.currentTarget.getBoundingClientRect().height;
254	        const hit = pianoRollHitTest(
255	          x,
256	          y,
257	          view,
258	          notes,
259	          canvasHeight,
260	          PR_VELOCITY_LANE_HEIGHT,
261	        );
262	
263	        if (tool === "pencil") {
264	          setCursor("crosshair");
265	        } else if (tool === "select") {
266	          switch (hit.kind) {
267	            case "note-body":
268	              setCursor("pointer");
269	              break;
270	            case "note-left-edge":
271	            case "note-right-edge":
272	              setCursor("ew-resize");
273	              break;
274	            default:
275	              setCursor("default");
276	              break;
277	          }
278	        } else {
279	          setCursor("default");
280	        }
281	        return;
282	      }
283	
284	      switch (drag.kind) {
285	        case "move-note": {
286	          setCursor("grabbing");
287	          const deltaPx = x - drag.startX;
288	          const deltaSec = deltaPx / view.pixelsPerSecond;
289	          const newTime = pianoRollSnapToGrid(
290	            Math.max(0, drag.origStartTime + deltaSec),
291	            state.bpm,
292	            gridSnap,
293	          );
294	          const newPitch = yToPitch(y, view);
295	          state.moveNoteEvent(drag.clipId, drag.noteId, newTime, newPitch);
296	          break;
297	        }
298	        case "resize-note": {
299	          setCursor("ew-resize");
300	          const deltaPx = x - drag.startX;
301	          const deltaSec = deltaPx / view.pixelsPerSecond;
302	          if (drag.edge === "left") {
303	            const origEnd = drag.origStartTime + drag.origDuration;
304	            const newStartTime = Math.max(
305	              0,
306	              Math.min(drag.origStartTime + deltaSec, origEnd - 0.01),
307	            );
308	            const newDuration = origEnd - newStartTime;
309	            state.moveNoteEvent(
310	              drag.clipId,
311	              drag.noteId,
312	              newStartTime,
313	              // Keep pitch unchanged -- look up current pitch
314	              getNotes().find((n) => n.id === drag.noteId)?.pitch ?? 0,
315	            );
316	            state.resizeNoteEvent(drag.clipId, drag.noteId, newDuration);
317	          } else {
318	            const newDuration = Math.max(0.01, drag.origDuration + deltaSec);
319	            state.resizeNoteEvent(drag.clipId, drag.noteId, newDuration);
320	          }
321	          break;
322	        }
323	        case "draw-note": {
324	          // Extend note duration as user drags
325	          const currentTime = xToSeconds(x, view);
326	          const snappedEnd = pianoRollSnapToGrid(
327	            currentTime,
328	            state.bpm,
329	            gridSnap,
330	          );
331	          const newDuration = Math.max(
332	            gridDuration(state.bpm, gridSnap),
333	            snappedEnd - drag.startTime,
334	          );
335	          state.resizeNoteEvent(drag.clipId, drag.noteId, newDuration);
336	          break;
337	        }
338	        case "rubber-band": {
339	          if (clipId === null) break;
340	          const notes = getNotes();
341	          const selected = lassoSelectNotes(
342	            drag.startX,
343	            drag.startY,
344	            x,
345	            y,
346	            view,
347	            notes,
348	          );
349	          state.setSelectedNoteIds([...selected]);
350	          break;
351	        }
352	      }
353	    },
354	    [clipId, view, tool, gridSnap, getCanvasPos, getNotes],
355	  );
356	
357	  const onPointerUp = useCallback(
358	    (e: React.PointerEvent<HTMLCanvasElement>): void => {
359	      const drag = dragRef.current;
360	
361	      if (drag.kind === "move-note") {
362	        const notes = getNotes();
363	        const note = notes.find((n) => n.id === drag.noteId);
364	        if (
365	          note !== undefined &&
366	          (note.startTime !== drag.origStartTime ||
367	            note.pitch !== drag.origPitch)
368	        ) {
369	          const cmd = new MoveNoteCommand(
370	            drag.clipId,
371	            drag.noteId,
372	            note.startTime,
373	            note.pitch,
374	            drag.origStartTime,
375	            drag.origPitch,
376	          );
377	          // Store is already updated during drag -- just record for undo
378	          sharedUndoManager.push(cmd);
379	        }
380	      } else if (drag.kind === "resize-note") {
381	        const notes = getNotes();
382	        const note = notes.find((n) => n.id === drag.noteId);
383	        if (note !== undefined) {
384	          if (drag.edge === "left") {
385	            // Left-edge drag changed both startTime and duration
386	            const cmds: UndoCommand[] = [];
387	            if (note.startTime !== drag.origStartTime) {
388	              cmds.push(
389	                new MoveNoteCommand(
390	                  drag.clipId,
391	                  drag.noteId,
392	                  note.startTime,
393	                  note.pitch,
394	                  drag.origStartTime,
395	                  note.pitch,
396	                ),
397	              );
398	            }
399	            if (note.duration !== drag.origDuration) {
400	              cmds.push(
401	                new ResizeNoteCommand(
402	                  drag.clipId,
403	                  drag.noteId,
404	                  note.duration,
405	                  drag.origDuration,
406	                ),
407	              );
408	            }
409	            if (cmds.length > 0) {
410	              const batch = new BatchNoteCommand(cmds);
411	              sharedUndoManager.push(batch);
412	            }
413	          } else if (note.duration !== drag.origDuration) {
414	            const cmd = new ResizeNoteCommand(
415	              drag.clipId,
416	              drag.noteId,
417	              note.duration,
418	              drag.origDuration,
419	            );
420	            sharedUndoManager.push(cmd);
421	          }
422	        }
423	      } else if (drag.kind === "draw-note") {
424	        // If the user dragged to extend the note, capture a resize command
425	        // so redo restores the final dragged duration (not the initial grid-step size)
426	        const notes = getNotes();
427	        const note = notes.find((n) => n.id === drag.noteId);
428	        if (note !== undefined) {
429	          const state = useDawStore.getState();
430	          const initialDuration = gridDuration(state.bpm, gridSnap);
431	          if (note.duration !== initialDuration) {
432	            const cmd = new ResizeNoteCommand(
433	              drag.clipId,
434	              drag.noteId,
435	              note.duration,
436	              initialDuration,
437	            );
438	            sharedUndoManager.push(cmd);
439	          }
440	        }
441	      }
442	
443	      if (drag.kind !== "idle") {
444	        e.currentTarget.releasePointerCapture(e.pointerId);
445	      }
446	      dragRef.current = { kind: "idle" };
447	
448	      // Restore tool-appropriate cursor
449	      if (tool === "pencil") {
450	        setCursor("crosshair");
451	      } else {
452	        setCursor("default");
453	      }
454	    },
455	    [tool, gridSnap, getNotes],
456	  );
457	
458	  const deleteSelectedNotes = useCallback((): void => {
459	    if (clipId === null) return;
460	    const state = useDawStore.getState();
461	    const selected = state.selectedNoteIds;
462	    if (selected.length === 0) return;
463	
464	    const commands = selected.map(
465	      (noteId) => new RemoveNoteCommand(clipId, noteId),
466	    );
467	    const batch = new BatchNoteCommand(commands);
468	    batch.execute();
469	    sharedUndoManager.push(batch);
470	    state.setSelectedNoteIds([]);
471	  }, [clipId]);
472	
473	  return {
474	    cursor,
475	    onPointerDown,
476	    onPointerMove,
477	    onPointerUp,
478	    deleteSelectedNotes,
479	  };
480	}
