import { useEffect, useState } from "react";
import styles from "./ActionToast.module.css";

const TOAST_DURATION = 1200;
const FADE_DURATION = 100;

type ActionToastProps = {
  message: string | null;
};

export function ActionToast({ message }: ActionToastProps): React.JSX.Element | null {
  const [display, setDisplay] = useState<{
    text: string;
    fading: boolean;
  } | null>(null);

  useEffect(() => {
    if (message === null) return;

    const text = message.replace(/#\d+$/, "");
    setDisplay({ text, fading: false });

    const fadeTimer = setTimeout(() => {
      setDisplay((prev) => (prev !== null ? { ...prev, fading: true } : null));
    }, TOAST_DURATION - FADE_DURATION);

    const hideTimer = setTimeout(() => {
      setDisplay(null);
    }, TOAST_DURATION);

    return () => {
      clearTimeout(fadeTimer);
      clearTimeout(hideTimer);
    };
  }, [message]);

  if (display === null) return null;

  const toastClass = styles["toast"] ?? "";
  const hidingClass = styles["hiding"] ?? "";

  return (
    <div
      className={`${toastClass}${display.fading ? ` ${hidingClass}` : ""}`}
      role="status"
      aria-live="polite"
    >
      {display.text}
    </div>
  );
}

