import { useEffect, useRef, useState } from "react";
import styles from "./ActionToast.module.css";

const TOAST_DURATION = 1200;
const FADE_DURATION = 100;

type ActionToastProps = {
  message: string | null;
};

export function ActionToast({ message }: ActionToastProps): React.JSX.Element | null {
  const [phase, setPhase] = useState<"hidden" | "visible" | "fading">("hidden");
  const lastMessageRef = useRef<string | null>(null);
  const displayRef = useRef<string | null>(null);

  // Track when message changes (new toast trigger)
  if (message !== null && message !== lastMessageRef.current) {
    lastMessageRef.current = message;
    displayRef.current = message;
    // Synchronous state update during render (not in effect) is fine
    if (phase !== "visible") {
      setPhase("visible");
    }
  }

  useEffect(() => {
    if (phase !== "visible") return;

    const fadeTimer = setTimeout(() => {
      setPhase("fading");
    }, TOAST_DURATION - FADE_DURATION);

    const hideTimer = setTimeout(() => {
      setPhase("hidden");
    }, TOAST_DURATION);

    return () => {
      clearTimeout(fadeTimer);
      clearTimeout(hideTimer);
    };
  }, [phase, lastMessageRef.current]);

  if (phase === "hidden") return null;

  const toastClass = styles["toast"] ?? "";
  const hidingClass = styles["hiding"] ?? "";
  const displayText = (displayRef.current ?? "").replace(/#\d+$/, "");

  return (
    <div
      className={`${toastClass}${phase === "fading" ? ` ${hidingClass}` : ""}`}
      role="status"
      aria-live="polite"
    >
      {displayText}
    </div>
  );
}

